INSERT INTO resources (name, category_id, subcategory, description, address, city, county, state, zip_code, phone, website, hours, accepts_uninsured, sliding_scale, medicaid, medicare, private_insurance, walk_ins_welcome, appointments, telehealth, cost_free, cost_estimate_min, cost_estimate_max, languages, accessibility, services, specialties, audiences, rating, photo_url, source) VALUES
('Behavioral Health Resources (BHR)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'South Puget Sound''s largest comprehensive provider of behavioral health and substance use disorder treatment services since 1956. Serves residents of Thurston, Mason, and Grays Harbor Counties through adult and children''s outpatient programs. Sliding-fee scale available.', '3857 Martin Way East', 'Olympia', 'Thurston', 'WA', '98506', '(360) 704-7170', 'https://www.bhr.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{South Puget Sound''s largest comprehensive provider of behavioral health and substance use disorder treatment services since 1956,Serves residents of Thurston,Mason,and Grays Harbor Counties through adult and children''s outpatient programs,Sliding-fee scale available}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Frontier Behavioral Health', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Community behavioral health agency serving Spokane and eastern Washington. Provides adult outpatient services, child and family services, crisis intervention and ITA evaluations, inpatient evaluation and treatment, the 988 crisis line, PACT, wraparound intensive services (WISe), DBT programs, forensic services, and housing support.', '107 South Division Street', 'Spokane', 'Spokane', 'WA', '99202', '(509) 838-4651', 'https://fbhwa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Community behavioral health agency serving Spokane and eastern Washington,Provides adult outpatient services,child and family services,crisis intervention and ITA evaluations,inpatient evaluation and treatment}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sea Mar Community Health Centers - Seattle Behavioral Health Clinic', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'State-licensed community mental health agency providing culturally competent behavioral health services including assessment, individual and group therapy, psychiatric medication evaluation and management, and case management for adults and children. Specializes in service to Latino and underserved communities; serves regardless of ability to pay.', '8801 14th Avenue South', 'Seattle', 'King', 'WA', '98108', '(206) 764-4700', 'https://www.seamar.org/king-bh-seattle.html', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{State-licensed community mental health agency providing culturally competent behavioral health services including assessment,individual and group therapy,psychiatric medication evaluation and management,and case management for adults and children,Specializes in service to Latino and underserved communities; serves regardless of ability to pay}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sea Mar Community Health Centers - White Center Behavioral Health Clinic', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Outpatient behavioral health clinic offering mental health and medication-assisted treatment services in the White Center neighborhood of south Seattle. Part of the Sea Mar network of 90+ clinics across western Washington.', '9650 15th Avenue SW', 'Seattle', 'King', 'WA', '98106', '(206) 965-1055', 'https://www.seamar.org/king-bh-whitecenter.html', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Outpatient behavioral health clinic offering mental health and medication-assisted treatment services in the White Center neighborhood of south Seattle,Part of the Sea Mar network of 90+ clinics across western Washington}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Catholic Community Services of Western Washington - Seattle Office (Behavioral Health)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Provides child and family mental health counseling services, housing support, family and youth services, services for seniors and people with disabilities, and behavioral health programs across multiple counties in Western Washington.', '100 23rd Avenue South', 'Seattle', 'King', 'WA', '98144', '(206) 328-5696', 'https://ccsww.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Provides child and family mental health counseling services,housing support,family and youth services,services for seniors and people with disabilities,and behavioral health programs across multiple counties in Western Washington}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Catholic Community Services of Western Washington - Family Behavioral Health (Tacoma)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Licensed children''s mental health provider offering Wraparound services for children, youth, and families across King, Pierce, Kitsap, Skagit, Snohomish, Whatcom, and Grays Harbor Counties. CARF-accredited.', '1001 North J Street', 'Tacoma', 'Pierce', 'WA', '98403', '(253) 761-3856', 'https://ccsfamilybehavioralhealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Licensed children''s mental health provider offering Wraparound services for children,youth,and families across King,Pierce,Kitsap}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Compass Health - Everett Colby Office', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Adult outpatient services including individual, family, and group therapy as well as community support services. Compass Health is a leading behavioral health provider serving Snohomish, Skagit, Island, San Juan, and Whatcom Counties. Crisis line: 1-800-584-3578.', '2722 Colby Avenue', 'Everett', 'Snohomish', 'WA', '98201', '(425) 349-6804', 'https://www.compasshealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Adult outpatient services including individual,family,and group therapy as well as community support services,Compass Health is a leading behavioral health provider serving Snohomish,Skagit}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Compass Health - Snohomish Triage Center', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Short-stay crisis triage and stabilization facility providing a safe, recovery-oriented environment for individuals experiencing behavioral health crises. Offers crisis assessment, stabilization, and connection to ongoing treatment services. Admissions: (888) 693-7200.', '3322 Broadway', 'Everett', 'Snohomish', 'WA', '98201', '(425) 249-2530', 'https://www.compasshealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Short-stay crisis triage and stabilization facility providing a safe,recovery-oriented environment for individuals experiencing behavioral health crises,Offers crisis assessment,stabilization,and connection to ongoing treatment services}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Volunteers of America Western Washington - Behavioral Health & Crisis Services', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Comprehensive human services nonprofit providing 24/7 behavioral health and crisis line services (including the 988 Suicide & Crisis Lifeline) for Snohomish, Skagit, San Juan, Island, and Whatcom Counties. Offers telephone crisis intervention, emotional support, suicide prevention, and specialized lines for veterans, Spanish speakers, and American Indians/Alaska Natives. North Sound Regional Crisis Line: (800) 584-3578.', '2802 Broadway', 'Everett', 'Snohomish', 'WA', '98201', '(425) 259-3191', 'https://www.voaww.org/behavioralhealth', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Comprehensive human services nonprofit providing 24/7 behavioral health and crisis line services (including the 988 Suicide & Crisis Lifeline) for Snohomish,Skagit,San Juan,Island,and Whatcom Counties}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Community Health Center of Snohomish County - Central Everett Clinic', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Federally supported community health center providing integrated behavioral health care including mental health counseling and behavioral health services alongside primary medical and dental care for Snohomish County residents regardless of ability to pay.', '4201 Rucker Avenue', 'Everett', 'Snohomish', 'WA', '98203', '(425) 358-2700', 'https://www.chcsno.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Federally supported community health center providing integrated behavioral health care including mental health counseling and behavioral health services alongside primary medical and dental care for Snohomish County residents regardless of ability to pay}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('NAMI North Central Washington', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Independent NAMI affiliate serving North Central Washington. Offers NAMI Provider education programs, peer-led support groups, mental health education, and community presentations. Call or text for information.', '1212 Connection Street', 'Wenatchee', 'Chelan', 'WA', '98801', '(509) 663-8282', 'https://namincwa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Independent NAMI affiliate serving North Central Washington,Offers NAMI Provider education programs,peer-led support groups,mental health education,and community presentations}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Community Health Care - Puyallup Health Center (Dental)', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC providing comprehensive dental care (preventive, restorative, emergency, minor oral surgery) for all ages across five dental clinics in Pierce County. Accepts Apple Health (Medicaid); sliding-fee discounts for the uninsured. No one denied care due to inability to pay.', '201 West Main Street', 'Puyallup', 'Pierce', 'WA', '98371', '(253) 722-2151', 'https://www.commhealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC providing comprehensive dental care (preventive,restorative,emergency,minor oral surgery) for all ages across five dental clinics in Pierce County,Accepts Apple Health (Medicaid); sliding-fee discounts for the uninsured}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779705/pexels-photo-3779705.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Neighborcare Health - 45th Street Clinic (Dental)', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC dental clinic in Wallingford offering general dentistry, emergency care, extractions, fillings, crowns, bridges, dentures, and root canals for adults and children. Accepts WA Apple Health (Medicaid), Medicare Advantage, and private insurance; sliding-scale fees for the uninsured.', '1629 North 45th Street', 'Seattle', 'King', 'WA', '98103', '(206) 548-2964', 'https://neighborcare.org/clinics/45th-street', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC dental clinic in Wallingford offering general dentistry,emergency care,extractions,fillings,crowns}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/5212295/pexels-photo-5212295.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Neighborcare Health - Rainier Beach Medical & Dental Clinic', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC providing general dentistry, emergency dental care, oral/maxillofacial surgery, dental bridges, and dentures. Patients seen regardless of ability to pay. Accepts WA Apple Health (Medicaid), most Medicare Advantage plans, and private insurance; sliding-scale fees available.', '9245 Rainier Avenue South', 'Seattle', 'King', 'WA', '98118', '(206) 722-8444', 'https://neighborcare.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC providing general dentistry,emergency dental care,oral/maxillofacial surgery,dental bridges,and dentures}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779706/pexels-photo-3779706.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sea Mar Community Health Centers - Seattle Dental Clinic', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC dental clinic in South Park offering exams, urgent/emergency care, x-rays, restorations (fillings), scaling, composites, extractions, root canals, limited orthodontics, and oral health education for all ages. Accepts Apple Health (Medicaid), Medicare, and private insurance; sliding-fee scale for the uninsured.', '8915 14th Avenue South', 'Seattle', 'King', 'WA', '98108', '(206) 762-3263', 'https://www.seamar.org/services-dental.html', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC dental clinic in South Park offering exams,urgent/emergency care,x-rays,restorations (fillings),scaling}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779705/pexels-photo-3779705.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sea Mar Community Health Centers - Vancouver Dental Clinic', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC dental clinic offering preventive exams, cleanings, sealants, fluoride, x-rays, fillings, scaling, extractions, and emergency/urgent care. Saturday hours reserved for children and pregnant women. Accepts Apple Health (Medicaid), Medicare, and private insurance; sliding-fee scale for uninsured.', '1412 NE 88th Street', 'Vancouver', 'Clark', 'WA', '98665', '(360) 574-4074', 'https://www.seamar.org/clark-dental-vancouver.html', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC dental clinic offering preventive exams,cleanings,sealants,fluoride,x-rays}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779706/pexels-photo-3779706.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('International Community Health Services (ICHS) - International District Medical & Dental Clinic', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC flagship clinic in Seattle''s Chinatown-International District providing comprehensive adult and pediatric dental care, medical, behavioral health, pharmacy, and WIC. Culturally appropriate, multilingual care. Accepts Apple Health (Medicaid), Medicare, and private insurance; sliding-fee discounts available.', '720 8th Avenue South', 'Seattle', 'King', 'WA', '98104', '(206) 788-3700', 'https://www.ichs.com/locations/international-district-medical-and-dental-clinic', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC flagship clinic in Seattle''s Chinatown-International District providing comprehensive adult and pediatric dental care,medical,behavioral health,pharmacy,and WIC}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6642765/pexels-photo-6642765.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('International Community Health Services (ICHS) - Shoreline Medical & Dental Clinic', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC offering adult and pediatric medical care plus comprehensive adult and pediatric dental care and outpatient behavioral health. Serves Shoreline, Lake City, Lake Forest Park, Bothell, Lynnwood, and Edmonds residents. Accepts Apple Health (Medicaid); sliding-fee scale.', '13039 Meridian Avenue North', 'Shoreline', 'King', 'WA', '98133', '(206) 788-3700', 'https://www.ichs.com/locations/shoreline-medical-and-dental-clinic', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC offering adult and pediatric medical care plus comprehensive adult and pediatric dental care and outpatient behavioral health,Serves Shoreline,Lake City,Lake Forest Park,Bothell}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6642765/pexels-photo-6642765.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Yakima Neighborhood Health Services - Anita Monoian Campus (Dental)', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC offering comprehensive family dentistry including exams, digital x-rays, cleanings, fillings, crowns, extractions, denture assistance, and emergency dental care for all ages. Same-day appointments available; Saturday hours. Accepts Apple Health (Medicaid), Medicare, and private insurance; discounted sliding-fee scale for uninsured.', '12 South 8th Street', 'Yakima', 'Yakima', 'WA', '98901', '(509) 574-5562', 'https://ynhs.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC offering comprehensive family dentistry including exams,digital x-rays,cleanings,fillings,crowns}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779706/pexels-photo-3779706.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Columbia Valley Community Health - Wenatchee Medical, Dental & Behavioral', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC providing comprehensive dental care for children (6 months through age 20) and adults including exams, cleanings, x-rays, fillings, and urgent dental care. Emphasis on at-risk populations. Accepts Medicaid (Apple Health) dental; sliding-fee scale available.', '600 Orondo Avenue, Suite 1', 'Wenatchee', 'Chelan', 'WA', '98801', '(509) 662-6000', 'https://cvch.org/location/wenatchee-medical-dental-behavioral', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC providing comprehensive dental care for children (6 months through age 20) and adults including exams,cleanings,x-rays,fillings,and urgent dental care}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779705/pexels-photo-3779705.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified') ON CONFLICT DO NOTHING;